use strict;
use warnings;
use PDF::API2;
use Text::Unidecode;

# Function to extract text from a PDF
sub extract_text {
    my ($file) = @_;
    my $pdf = PDF::API2->open($file);
    my $pages = $pdf->pages;

    my $text = '';

    for (my $i = 1; $i <= $pages; $i++) {
        my $page = $pdf->page($i);
        my $text_page = $page->mediabox->text();
        $text .= $text_page;
    }

    return $text;
}

